  ('disabled-64311456-moex-00217', 'disabled-64311456', 'disabled-64311456-moex-112-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於現行法中對於公務員不得為一定行為之義務，下列何者錯誤？', '["關於收受餽贈之禁止事項，僅限於關於其本身職務之範圍內", "關於兼營商業之禁止事項，並不禁止個人合法投資理財行為", "關於兼職之禁止事項，即便是依法令兼職者也不得兼薪", "關於濫權之禁止，包括非因職務需要恣意支用公款之行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "eb1ee0cbefd2", "answer_pdf_sha1": "42481371dba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
