  ('disabled-64311456-moex-00219', 'disabled-64311456', 'disabled-64311456-moex-112-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於公務人員之保障，下列何者正確？', '["就業務性質特殊機關所屬公務人員之服勤時數及超時服勤，應為合理之 規定，予以適當之評價與補償", "公務人員之身分應予保障，非依法律或法律明確授權之法規命令，不得 剝奪", "公務人員因機關裁撤時，不符退休條件者，應一律予以資遣", "公務人員就影響其權益之公權力措施，於申訴、再申訴後，不得續向法 院請求救濟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "eb1ee0cbefd2", "answer_pdf_sha1": "42481371dba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
