  ('disabled-64311456-moex-00221', 'disabled-64311456', 'disabled-64311456-moex-112-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '長官於監督範圍內所發之命令違反刑事法律者，公務員應如何處置？', '["因依法令之行為不罰，故公務員仍應服從", "公務員負報告義務，如長官之命令以書面署名下達時，即應服從", "公務員應向長官陳述意見，但無服從之義務", "公務員應越級上報"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "eb1ee0cbefd2", "answer_pdf_sha1": "42481371dba4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
